import { useState } from 'react';

function Profile() {
  const [user, setUser] = useState({ name: 'Alice', age: 30 });

  function handleBirthdayBug() {
    // BUG: mutating the existing object
    user.age += 1;
    setUser(user); // same reference → React skips re-render!
  }

  function handleBirthday() {
    // CORRECT: create a new object
    setUser({ ...user, age: user.age + 1 });
    // new reference → React re-renders ✓
  }

  return (
    <div>
      <p>{user.name} is {user.age}</p>
      <button onClick={handleBirthdayBug}>Birthday (broken)</button>
      <button onClick={handleBirthday}>Birthday (fixed)</button>
    </div>
  );
}

const user = { name: 'Alice', age: 30, role: 'admin' };

// Update one property
const older = { ...user, age: 31 };
// { name: 'Alice', age: 31, role: 'admin' }

// Update multiple properties
const promoted = { ...user, age: 31, role: 'superadmin' };

// Add a property
const withEmail = { ...user, email: 'alice@example.com' };

// Remove a property (rest syntax)
const { role, ...noRole } = user;
// noRole = { name: 'Alice', age: 30 }

const state = {
  user: { name: 'Alice', address: { city: 'London', zip: 'EC1' } },
  theme: 'dark',
};

// BUG: shallow copy — state.user.address is still the same object
const bad = { ...state, user: { ...state.user } };
bad.user.address.city = 'Paris'; // mutates original!

// CORRECT: spread at every level you're changing
const good = {
  ...state,
  user: {
    ...state.user,
    address: { ...state.user.address, city: 'Paris' },
  },
};

function TodoList() {
  const [todos, setTodos] = useState([
    { id: 1, text: 'Buy milk', done: false },
    { id: 2, text: 'Walk dog', done: false },
  ]);

  // Add
  function addTodo(text) {
    setTodos([...todos, { id: Date.now(), text, done: false }]);
  }

  // Remove
  function removeTodo(id) {
    setTodos(todos.filter((t) => t.id !== id));
  }

  // Toggle
  function toggleTodo(id) {
    setTodos(todos.map((t) =>
      t.id === id ? { ...t, done: !t.done } : t
    ));
  }

  return (
    <ul>
      {todos.map((t) => (
        <li key={t.id}>
          <input type="checkbox" checked={t.done} onChange={() => toggleTodo(t.id)} />
          {t.text}
          <button onClick={() => removeTodo(t.id)}>✕</button>
        </li>
      ))}
    </ul>
  );
}

// Pure function — same input always produces same output, no side effects
function formatPrice(amount, currency = 'USD') {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency })
    .format(amount);
}

formatPrice(9.99);        // '$9.99' — always
formatPrice(9.99, 'EUR'); // '€9.99' — always

// Impure — reads external state (Math.random, Date) → different output each time
function generateId() {
  return Math.random().toString(36).slice(2); // not pure
}

// Impure — has side effects (mutates argument, writes to console)
function addAndLog(arr, item) {
  arr.push(item);       // mutates argument
  console.log(arr);     // side effect
  return arr;
}

// Pure component — same props → same output
function Greeting({ name, count }) {
  return (
    <p>
      Hello, {name}! You have {count} message{count !== 1 ? 's' : ''}.
    </p>
  );
}

// Impure component — produces different JSX on every render
let renderCount = 0;
function ImpureGreeting({ name }) {
  renderCount++;  // side effect during render!
  return <p>Hello {name}, render #{renderCount}</p>;
  // React may render this more than once — renderCount will be wrong
}

// Pure reducer — no mutation, returns new state
function cartReducer(state, action) {
  switch (action.type) {
    case 'ADD_ITEM':
      return { ...state, items: [...state.items, action.item] };

    case 'REMOVE_ITEM':
      return {
        ...state,
        items: state.items.filter((i) => i.id !== action.id),
      };

    case 'UPDATE_QTY':
      return {
        ...state,
        items: state.items.map((i) =>
          i.id === action.id ? { ...i, qty: action.qty } : i
        ),
      };

    default:
      return state; // unknown action → return unchanged state
  }
}

const state = {
  user: { name: 'Alice' },
  settings: { theme: 'dark', lang: 'en' }, // unchanged subtree
  cart: { items: [] },
};

// Only user becomes a new object; settings and cart are shared (same reference)
const next = { ...state, user: { ...state.user, name: 'Bob' } };

console.log(next.settings === state.settings); // true — shared reference
console.log(next.cart    === state.cart);     // true — shared reference
console.log(next.user    === state.user);     // false — new object

import { produce } from 'immer';

const state = {
  user: { address: { city: 'London', zip: 'EC1' } },
};

// produce creates a draft proxy — mutations to draft produce a new immutable state
const next = produce(state, (draft) => {
  draft.user.address.city = 'Paris'; // looks like mutation, isn't!
});

console.log(next.user.address.city);   // 'Paris'
console.log(state.user.address.city);  // 'London' — original unchanged

// useImmer hook (from the 'use-immer' package) wraps useState with produce
import { useImmer } from 'use-immer';

function NestedForm() {
  const [state, updateState] = useImmer({
    user: { name: 'Alice', address: { city: 'London' } },
  });

  function handleCityChange(city) {
    updateState((draft) => {
      draft.user.address.city = city;
    });
  }

  return (
    <input
      value={state.user.address.city}
      onChange={(e) => handleCityChange(e.target.value)}
    />
  );
}

const config = Object.freeze({
  apiBase: 'https://api.example.com',
  timeout: 5000,
});

config.timeout = 9999; // silently ignored (or throws in strict mode)
console.log(config.timeout); // 5000 — unchanged

// TypeScript's 'as const' provides compile-time immutability:
const ROUTES = {
  home: '/',
  about: '/about',
} as const;
// ROUTES.home = '/new'; // TypeScript error

// BUG: functional update form — but still mutating!
setItems((prev) => {
  prev.push(newItem); // mutates prev — do NOT do this
  return prev;        // same reference → no re-render
});

// CORRECT: always return a new array
setItems((prev) => [...prev, newItem]);

// Looks like a copy, but items inside are shared references
const copy = [...originalArray];
copy[0].name = 'mutated'; // mutates the object inside originalArray too!

// For arrays of objects, spread each element if you need independence:
const deepCopy = originalArray.map((item) => ({ ...item }));

// BUG: mutating in event handler
function handleSubmit() {
  formData.name = inputRef.current.value; // mutates formData directly
  setFormData(formData); // same reference → no re-render
}

// CORRECT
function handleSubmit() {
  setFormData({ ...formData, name: inputRef.current.value });
}

import { useState, useMemo, useCallback } from 'react';

function ProductList({ products }) {
  const [filter, setFilter] = useState('');

  // useMemo only re-runs when products or filter changes (by reference/value)
  const filtered = useMemo(
    () => products.filter((p) => p.name.includes(filter)),
    [products, filter]  // products must be a new array when it changes
  );

  // useCallback memoises the function — same reference between renders
  const handleSelect = useCallback((id) => {
    console.log('Selected:', id);
  }, []); // no deps → stable function reference

  return (
    <>
      <input value={filter} onChange={(e) => setFilter(e.target.value)} />
      {filtered.map((p) => (
        <ProductRow key={p.id} product={p} onSelect={handleSelect} />
      ))}
    </>
  );
}

// React.memo skips re-render if props are referentially equal
const ProductRow = React.memo(function ProductRow({ product, onSelect }) {
  return <div onClick={() => onSelect(product.id)}>{product.name}</div>;
});

// stateUtils.js — pure functions for common state operations

export function addItem(list, item) {
  return [...list, item];
}

export function removeById(list, id) {
  return list.filter((x) => x.id !== id);
}

export function updateById(list, id, patch) {
  return list.map((x) => (x.id === id ? { ...x, ...patch } : x));
}

export function moveItem(list, fromIndex, toIndex) {
  const copy = [...list];
  const [removed] = copy.splice(fromIndex, 1);
  copy.splice(toIndex, 0, removed);
  return copy;
}

// Component stays clean — all state logic is in pure functions
import { addItem, removeById, updateById } from './stateUtils';

function TaskBoard() {
  const [tasks, setTasks] = useState([]);

  const handleAdd    = (task)       => setTasks((t) => addItem(t, task));
  const handleRemove = (id)         => setTasks((t) => removeById(t, id));
  const handleUpdate = (id, patch)  => setTasks((t) => updateById(t, id, patch));

  // ...
}

import { describe, it, expect } from 'vitest';
import { addItem, removeById, updateById } from './stateUtils';

describe('addItem', () => {
  it('returns a new array with the item appended', () => {
    const original = [{ id: 1 }];
    const result = addItem(original, { id: 2 });
    expect(result).toEqual([{ id: 1 }, { id: 2 }]);
    expect(result).not.toBe(original); // new reference
  });
});

describe('removeById', () => {
  it('returns array without the matched item', () => {
    const list = [{ id: 1 }, { id: 2 }, { id: 3 }];
    expect(removeById(list, 2)).toEqual([{ id: 1 }, { id: 3 }]);
  });

  it('does not mutate the original', () => {
    const list = [{ id: 1 }];
    removeById(list, 1);
    expect(list).toHaveLength(1); // original unchanged
  });
});

describe('updateById', () => {
  it('applies patch to matching item only', () => {
    const list = [{ id: 1, done: false }, { id: 2, done: false }];
    const result = updateById(list, 1, { done: true });
    expect(result[0].done).toBe(true);
    expect(result[1].done).toBe(false); // untouched
  });
});
